SELECT ?athlete (COUNT(DISTINCT ?olympic) AS ?count) WHERE {
  wd:Q1434242 wdt:P1556 ?athlete .
  ?athlete wdt:P21 wd:Q6581072 .
  ?athlete wdt:P27 wd:Q78 .
  ?athlete wdt:P646 ?olympic .
} GROUP BY ?athlete

SELECT ?event WHERE {
  ?event wdt:P31 wd:Q395541.
  ?event wdt:P2399 wd:Q82513.
  ?event wdt:P585 ?eventDate.
  FILTER(YEAR(?eventDate) = 1997)
}

SELECT (COUNT(DISTINCT ?olympic) AS ?count) WHERE {
  ?event rdfs:label ?eventLabel.
  FILTER(LANG(?eventLabel) = 'en').
  FILTER(CONTAINS(LCASE(?eventLabel), '1997')).
  FILTER(CONTAINS(LCASE(?eventLabel), 'judo championships')).
  ?event p:P534 ?participant;
        ps:P534 ?athlete.
  ?athlete wdt:P27 wd:Q78.
  ?athlete p:P198 ?olympicStatement;
          ps:P198 ?olympic.
}

